mapper.update:
update notice
title = #{title}, content = #{content}, type = #{type}, scope = #{scope}, update_time = now()
where id = #{id}

mapper.select:
select n.id, n.title, t.name as publisher_name, n.create_time as publish_time, n.type, n.scope, n.status, n.create_time
from notice n
left join teacher t on n.publisher_id = t.id

    n.title like CONCAT('%', #{title}, '%')
    and n.type = #{type}
    and n.status = #{status}

select n.id, n.title, n.content, n.publisher_id, t.name as publisher_name, n.create_time as publish_time, n.type,
       n.scope, n.status, n.create_time, n.update_time
from notice n
left join teacher t on n.publisher_id = t.id
where n.status = '发布'
  and (
      n.scope = '全部'

          or n.scope = #{className}


          or n.scope = #{majorName}


          or n.scope = #{collegeName}

  )
order by n.create_time desc

select count(*)
from notice n
where n.status = '发布'
  and (
      n.scope = '全部'

          or n.scope = #{className}


          or n.scope = #{majorName}


          or n.scope = #{collegeName}

  )
